define(["core/ajax","core/notification"],function(Ajax,Notification){var envId=0;function escapeHtml(s){var d=document.createElement("div");d.textContent=s||"";return d.innerHTML}

function loadInstanceCount(className,el){if(!envId){el.textContent="-";return}Ajax.call([{methodname:"local_rangeos_get_class_instances",args:{envid:envId,classid:className}}])[0].then(function(r){el.textContent=r.total+" instances";if(r.instances.length>0&&r.instances[0].scenarioid){var row=el.closest("tr[data-classname]");if(row){row.dataset.scenarioid=r.instances[0].scenarioid}}}).catch(function(){el.textContent="Error loading"})}

function showClassInstances(className,rangeId){var detail=document.getElementById("class-instances-detail");var title=document.getElementById("class-instances-title");var body=document.getElementById("class-instances-body");detail.dataset.rangeid=rangeId||"";detail.dataset.classname=className;title.textContent="Class: "+className;body.innerHTML='<tr><td colspan="6">Loading...</td></tr>';detail.style.display="";Ajax.call([{methodname:"local_rangeos_get_class_instances",args:{envid:envId,classid:className}}])[0].then(function(r){if(!r.instances.length){body.innerHTML='<tr><td colspan="6" class="text-muted">No instances found.</td></tr>';return}body.innerHTML="";r.instances.forEach(function(inst){var tr=document.createElement("tr");var sc=inst.status==="Ready"?"success":inst.status==="NotReady"?"warning":"secondary";var seat=inst.studentid?"Seat "+escapeHtml(inst.studentid):"";var asgn;if(inst.assigned){var nm=escapeHtml(inst.displayname||inst.username||"Unknown");var em=inst.email?'<br><small class="text-muted">'+escapeHtml(inst.email)+"</small>":"";asgn=nm+em}else{asgn='<span class="text-muted">Unassigned</span>'};tr.innerHTML="<td>"+seat+"</td><td>"+escapeHtml(inst.scenarioname)+"</td><td><span class=\"badge badge-"+sc+"\">"+escapeHtml(inst.status)+"</span></td><td>"+asgn+"</td><td><code class=\"small\">"+escapeHtml(inst.id)+"</code></td><td><button class=\"btn btn-sm btn-outline-danger\" data-action=\"delete-instance\" data-rangeid=\""+escapeHtml(rangeId||"")+"\" data-scenarioid=\""+escapeHtml(inst.id)+"\" data-classname=\""+escapeHtml(className)+"\" title=\"Delete this instance\">&times;</button></td>";body.appendChild(tr)})}).catch(Notification.exception)}

function deleteScenarioInstance(rangeId,scenarioId,className){if(!window.confirm("Delete this scenario instance? This cannot be undone."))return;Ajax.call([{methodname:"local_rangeos_delete_scenario_instance",args:{envid:envId,rangeid:rangeId,scenarioid:scenarioId}}])[0].then(function(){Notification.addNotification({message:"Scenario instance deleted.",type:"success"});showClassInstances(className,rangeId);document.querySelectorAll('.instance-count[data-classname="'+className+'"]').forEach(function(el){loadInstanceCount(className,el)})}).catch(Notification.exception)}

function buildLabel(a){var parts=[a.activityname];if(a.autitle&&a.autitle!==a.activityname)parts.push(a.autitle);if(a.scenarioname)parts.push(a.scenarioname);return parts.join(" — ")}

function showCreateClassModal(){var mid="ccm"+Date.now();var jq=window.jQuery||window.$;var w=document.createElement("div");w.innerHTML='<div class="modal fade" id="'+mid+'" tabindex="-1" role="dialog"><div class="modal-dialog modal-lg" role="document"><div class="modal-content"><div class="modal-header"><h5 class="modal-title">Create Class</h5><button type="button" class="close" aria-label="Close" id="'+mid+'-close"><span>&times;</span></button></div><div class="modal-body"><div class="form-group"><label>Class ID</label><input type="text" class="form-control" id="'+mid+'-classid" placeholder="e.g. cyber-101-spring-2026"></div><div class="form-group"><label>Activity / Scenario</label><select class="custom-select" id="'+mid+'-scenario"><option value="">Loading local activities...</option></select><small class="form-text text-muted" id="'+mid+'-scenario-detail"></small></div><div class="form-group"><label>Number of Seats</label><input type="number" class="form-control" id="'+mid+'-count" value="20" min="1" max="200"></div><div class="form-group"><label>End Date</label><input type="date" class="form-control" id="'+mid+'-enddate"><small class="form-text text-muted">Defaults to 6 months from today if not set.</small></div></div><div class="modal-footer"><button type="button" class="btn btn-secondary" id="'+mid+'-cancel">Cancel</button><button type="button" class="btn btn-primary" id="'+mid+'-save">Create</button></div></div></div></div>';document.body.appendChild(w);var mel=document.getElementById(mid);var sel=document.getElementById(mid+"-scenario");var det=document.getElementById(mid+"-scenario-detail");

Ajax.call([{methodname:"local_rangeos_get_local_activity_scenarios",args:{envid:envId}}])[0].then(function(r){sel.innerHTML='<option value="">-- Select an activity scenario --</option>';var acts=r.activities||[];if(!acts.length){sel.innerHTML='<option value="">No activities with scenario mappings found</option>';return}var lastCourse="";var optgroup=null;acts.forEach(function(a){if(a.coursename!==lastCourse){optgroup=document.createElement("optgroup");optgroup.label=a.coursename;sel.appendChild(optgroup);lastCourse=a.coursename}var opt=document.createElement("option");opt.value=a.scenariouuid;opt.textContent=buildLabel(a);(optgroup||sel).appendChild(opt)})}).catch(function(){sel.innerHTML='<option value="">Error loading activities</option>'});

sel.addEventListener("change",function(){var opt=sel.selectedOptions[0];det.textContent=(opt&&opt.value)?"UUID: "+opt.value:""});

jq(mel).modal("show");
document.getElementById(mid+"-close").addEventListener("click",function(){jq(mel).modal("hide")});
document.getElementById(mid+"-cancel").addEventListener("click",function(){jq(mel).modal("hide")});
var saveBtn=document.getElementById(mid+"-save");saveBtn.addEventListener("click",function(){var cid=document.getElementById(mid+"-classid").value.trim();var sid=sel.value;var cnt=parseInt(document.getElementById(mid+"-count").value,10);var edv=document.getElementById(mid+"-enddate").value;var enddate=edv?new Date(edv+"T23:59:59Z").toISOString():"";if(!cid||!sid||!cnt){Notification.addNotification({message:"Class ID, scenario, and seat count are required.",type:"error"});return}saveBtn.disabled=true;saveBtn.textContent="Creating...";Ajax.call([{methodname:"local_rangeos_create_class",args:{envid:envId,scenarioid:sid,classid:cid,count:cnt,enddate:enddate}}])[0].then(function(){jq(mel).modal("hide");Notification.addNotification({message:'Class "'+cid+'" has been queued for deployment with '+cnt+' seats. It may take a few minutes for instances to appear.',type:"success"});setTimeout(function(){window.location.reload()},3000)}).catch(function(err){saveBtn.disabled=false;saveBtn.textContent="Create";Notification.exception(err)})});jq(mel).on("hidden.bs.modal",function(){w.remove()})}

function showAddSeatsModal(className,knownScenarioId){var mid="asm"+Date.now();var jq=window.jQuery||window.$;var w=document.createElement("div");w.innerHTML='<div class="modal fade" id="'+mid+'" tabindex="-1" role="dialog"><div class="modal-dialog" role="document"><div class="modal-content"><div class="modal-header"><h5 class="modal-title">Add Seats: '+escapeHtml(className)+'</h5><button type="button" class="close" aria-label="Close" id="'+mid+'-close"><span>&times;</span></button></div><div class="modal-body"><div class="form-group"><label>Additional Seats</label><input type="number" class="form-control" id="'+mid+'-count" value="10" min="1" max="200"></div></div><div class="modal-footer"><button type="button" class="btn btn-secondary" id="'+mid+'-cancel">Cancel</button><button type="button" class="btn btn-primary" id="'+mid+'-save">Add Seats</button></div></div></div></div>';document.body.appendChild(w);var mel=document.getElementById(mid);jq(mel).modal("show");document.getElementById(mid+"-close").addEventListener("click",function(){jq(mel).modal("hide")});document.getElementById(mid+"-cancel").addEventListener("click",function(){jq(mel).modal("hide")});document.getElementById(mid+"-save").addEventListener("click",function(){var cnt=parseInt(document.getElementById(mid+"-count").value,10);if(!knownScenarioId){Notification.addNotification({message:"Could not determine the scenario for this class. Try viewing instances first.",type:"error"});return}if(!cnt||cnt<1){Notification.addNotification({message:"Count must be at least 1.",type:"error"});return}var sb=document.getElementById(mid+"-save");sb.disabled=true;sb.textContent="Adding...";Ajax.call([{methodname:"local_rangeos_create_class",args:{envid:envId,scenarioid:knownScenarioId,classid:className,count:cnt,enddate:""}}])[0].then(function(){jq(mel).modal("hide");Notification.addNotification({message:cnt+" seats added to "+className,type:"success"});document.querySelectorAll('.instance-count[data-classname="'+className+'"]').forEach(function(el){loadInstanceCount(className,el)});var detail=document.getElementById("class-instances-detail");if(detail&&detail.style.display!=="none"){showClassInstances(className,detail.dataset.rangeid||"")}}).catch(function(err){sb.disabled=false;sb.textContent="Add Seats";Notification.exception(err)})});jq(mel).on("hidden.bs.modal",function(){w.remove()})}

return{init:function(){var c=document.querySelector("[data-envid]");if(c){envId=parseInt(c.dataset.envid,10)||0}var es=document.getElementById("rangeos-env-select");if(es){envId=parseInt(es.value,10);es.addEventListener("change",function(e){envId=parseInt(e.target.value,10);var el=document.querySelector("[data-baseurl]");if(el){var u=el.dataset.baseurl;window.location.href=u+(u.indexOf("?")>=0?"&":"?")+"envid="+envId}})}document.querySelectorAll(".instance-count[data-classname]").forEach(function(el){loadInstanceCount(el.dataset.classname,el)});document.addEventListener("click",function(e){var b=e.target.closest('[data-action="create-class"]');if(b){e.preventDefault();showCreateClassModal();return}b=e.target.closest('[data-action="view-instances"]');if(b){e.preventDefault();showClassInstances(b.dataset.classname,b.dataset.rangeid||"");return}b=e.target.closest('[data-action="delete-class"]');if(b){e.preventDefault();if(!window.confirm('Delete class "'+b.dataset.classname+'"?'))return;Notification.addNotification({message:"Class deletion is not yet implemented via this UI.",type:"warning"});return}b=e.target.closest('[data-action="add-seats"]');if(b){e.preventDefault();var row=b.closest("tr[data-classname]");var sid=row?row.dataset.scenarioid||"":"";showAddSeatsModal(b.dataset.classname,sid);return}b=e.target.closest('[data-action="delete-instance"]');if(b){e.preventDefault();deleteScenarioInstance(b.dataset.rangeid||"",b.dataset.scenarioid,b.dataset.classname);return}})}};});
